const webhookData = $input.first().json;
// n8n Webhook encapsula los POST JSON dentro de `body`; conservar
// compatibilidad con ejecuciones manuales que entregan el objeto directo.
const input = webhookData.body ?? webhookData;
const job_id = input.job_id;
const reunion_id = input.reunion_id;
const file_url = input.file_url;
const file_type = input.file_type || 'audio';
const callback_url = input.callback_url;
const callback_secret = input.callback_secret;
if (!file_url) {
  throw new Error('No se recibió file_url. Revisa que el backend envíe la URL firmada.');
}
return [{ json: { job_id, reunion_id, file_url, file_type, callback_url, callback_secret } }];

let text = $input.first().json;
if (typeof text === 'string') {
  return [{ json: { transcript: text } }];
}
const keys = ['transcript', 'text', 'content', 'body'];
for (const key of keys) {
  if (text[key]) {
    return [{ json: { transcript: text[key] } }];
  }
}
return [{ json: { transcript: JSON.stringify(text) } }];

const data = $input.first().json;
const text = typeof data === 'string' ? data : (data.text || data.transcript || JSON.stringify(data));
return [{ json: { transcript: text } }];

const context = $('Parse input').first().json;
const transcript = $input.first().json.transcript || '';
const CHUNK_SIZE = 6000;
const OVERLAP = 300;
if (transcript.length <= CHUNK_SIZE) {
  return [{ json: { use_chunks: false, transcript, context } }];
}
const chunks = [];
let start = 0;
while (start < transcript.length) {
  const end = Math.min(start + CHUNK_SIZE, transcript.length);
  chunks.push(transcript.slice(start, end));
  if (end === transcript.length) break;
  start = end - OVERLAP;
}
return [{ json: { use_chunks: true, chunks, context } }];

const items = $input.all();
const chunks = items.map(i => i.json).filter(j => j.chunks && j.chunks.length).flatMap(j => j.chunks);
return chunks.map((chunk, idx) => ({ json: { chunk, index: idx + 1, total: chunks.length } }));

