const resp = $input.first().json;
const content = resp.choices?.[0]?.message?.content;
let parsed = {};
if (typeof content === 'string') {
  try { parsed = JSON.parse(content); } catch { parsed = {}; }
}
const result = {
  resumen: parsed.resumen || parsed.resumen_ejecutivo || content || '',
  resumen_ejecutivo: parsed.resumen_ejecutivo || parsed.resumen || '',
  decisiones: Array.isArray(parsed.decisiones) ? parsed.decisiones.join('\n') : (parsed.decisiones || ''),
  riesgos: Array.isArray(parsed.riesgos) ? parsed.riesgos.join('\n') : (parsed.riesgos || ''),
  proximos_pasos: Array.isArray(parsed.proximos_pasos) ? parsed.proximos_pasos.join('\n') : (parsed.proximos_pasos || ''),
  tareas: Array.isArray(parsed.tareas) ? parsed.tareas : []
};
const context = $('Parse input').first().json;
return [{ json: { ...result, job_id: context.job_id, callback_url: context.callback_url, callback_secret: context.callback_secret } }];

